INSERT INTO `chat_messages` VALUES
('97','18','0',NULL,'bot','Xin chào! Tôi là trợ lý ảo của Aurora Hotel Plaza. Tôi có thể giúp gì cho bạn về đặt phòng, dịch vụ hoặc thông tin khách sạn?','text','0',NULL,'1','2026-04-28 19:27:10','2026-04-28 19:27:10'),
('98','18','0','guest_a56ac85d724c52e9685c7dcf8b42c3b6','customer','Tư vấn đặt phòng giúp mình','text','0',NULL,'1','2026-04-28 19:27:51','2026-04-28 19:27:18'),
('99','18','0',NULL,'bot','Dạ, Aurora Hotel Plaza xin gửi lời chào thân thương đến bạn! Rất hân hạnh được hỗ trợ bạn lựa chọn tổ ấm hoàn hảo cho kỳ nghỉ sắp tới. ????\n\nHiện tại chúng mình đang có 13 loại phòng và căn hộ với thiết kế từ hiện đại đến cổ điển, Indochine đầy chất thơ. Hôm nay là ngày thường nên giá phòng đang ở mức **base_price** rất ưu đãi cho bạn đó ạ. Dưới đây là một số hạng phòng nổi bật để bạn tham khảo:\n\n**1. Hạng phòng Superior & Deluxe (Phù hợp khách lẻ, công tác)**\n- **Deluxe:** Không gian ấm cúng, tiện nghi với giá chỉ 1,900,000đ/đêm. [IMAGE: https://aurorahotelplaza.com/assets/img/deluxe/deluxe-room-aurora-1.jpg]\n- **Premium Deluxe Double:** Giường đôi rộng rãi, thiết kế thanh lịch, giá 1,900,000đ/đêm. [IMAGE: https://aurorahotelplaza.com/assets/img/premium-deluxe/premium-deluxe-aurora-hotel-1.jpg]\n- **Premium Deluxe Twin:** Hai giường đơn tiện lợi cho bạn đi cùng bạn bè, giá 1,900,000đ/đêm. [IMAGE: https://aurorahotelplaza.com/assets/img/premium-twin/premium-deluxe-twin-aurora-1.jpg]\n\n**2. Hạng Studio (Không gian mở, view đẹp, lãng mạn)**\n- **Indochine Studio:** Đậm chất Á Đông, check-in siêu ảnh, giá 1,850,000đ/đêm. [IMAGE: https://aurorahotelplaza.com/assets/img/indochine-studio-apartment/indochine-studio-apartment-1.jpg]\n- **Modern Studio:** Phong cách hiện đại, tối giản, giá 1,850,000đ/đêm. [IMAGE: https://aurorahotelplaza.com/assets/img/modern-studio-apartment/modern-studio-apartment-1.jpg]\n- **Aurora Studio:** View thành phố tuyệt đẹp, hạng sang với giá 2,300,000đ/đêm. [IMAGE: https://aurorahotelplaza.com/assets/img/vip/vip-room-aurora-hotel-1.jpg]\n\n**3. Hạng Căn hộ & Gia đình (Rộng rãi, có phòng khách, bếp nhỏ)**\n- **Indochine Family:** Lựa chọn số 1 cho gia đình, giá 2,550,000đ/đêm. [IMAGE: https://aurorahotelplaza.com/assets/img/indochine-family-apartment/indochine-family-apartment-1.jpg]\n- **Family Apartment:** Không gian riêng tư, trọn vẹn như ở nhà, giá 2,550,000đ/đêm. [IMAGE: https://aurorahotelplaza.com/assets/img/family-apartment/can-ho-family-aurora-hotel-3.jpg]\n\n*(Tất cả giá trên đã bao gồm phí dịch vụ 5% và VAT 8%, đồng thời khách lưu trú được miễn phí sử dụng Hồ bơi, Gym và Phòng hội nghị).*\n\nĐể mình tư vấn chính xác và chi tiết hơn, bạn có thể chia sẻ thêm:\n- Bạn đi cùng gia đình, bạn bè hay đi công tác?\n- Số lượng người lớn và trẻ em đi cùng?\n- Dự kiến ngày check-in và thời gian lưu trú?\n\n???? **Gợi ý thêm:** Nếu bạn cần xe đưa đón từ sân bay/nhà ga, chúng mình có dịch vụ xe riêng (500.000đ). Hoặc sau một ngày dài, bạn có thể thư giãn tại Spa hoặc ngắm thành phố về đêm tại Rooftop Bar của khách sạn nhé!\n\nBạn ưng ý với phong cách nào nhất để mình gửi chi tiết thêm cho bạn ạ?','text','0',NULL,'0',NULL,'2026-04-28 19:27:53'),
('105','20','0',NULL,'bot','Xin chào! Tôi là trợ lý ảo của Aurora Hotel Plaza. Tôi có thể giúp gì cho bạn về đặt phòng, dịch vụ hoặc thông tin khách sạn?','text','0',NULL,'1','2026-04-28 21:11:28','2026-04-28 21:11:28'),
('106','20','0','guest_78e4930f8bcf7b24a30be9ca6503b4ef','customer','Chào','text','0',NULL,'1','2026-04-29 09:04:15','2026-04-28 21:11:31'),
('107','20','0',NULL,'bot','Dạ, Aurora Hotel Plaza xin kính chào quý khách! ????\n\nChào mừng quý khách đến với Aurora Hotel Plaza - khách sạn 4 sao sang trọng tọa lạc tại TP. Biên Hòa, Đồng Nai. Quản gia của quý khách ở đây và sẵn sàng hỗ trợ bất cứ điều gì ạ! \n\nQuý khách đang muốn tìm hiểu về các loại phòng, cần hỗ trợ đặt phòng lưu trú, hay muốn trải nghiệm các dịch vụ như xe đưa đón, thư giãn Spa hay thưởng thức không gian tại Rooftop Bar? Quý khách hãy cho quản gia biết nhu cầu của mình nhé ạ!','text','0',NULL,'0',NULL,'2026-04-28 21:11:58'),
('108','21','0',NULL,'bot','Xin chào! Tôi là trợ lý ảo của Aurora Hotel Plaza. Tôi có thể giúp gì cho bạn về đặt phòng, dịch vụ hoặc thông tin khách sạn?','text','0',NULL,'1','2026-04-29 13:32:58','2026-04-29 13:32:58'),
('109','21','0','guest_b0c911d6da6cff1f3d3307506654da78','customer','em cần tư vấn dịch vụ outside catering','text','0',NULL,'1','2026-05-02 16:16:29','2026-04-29 13:33:14'),
('110','21','0',NULL,'bot','Dạ, Aurora Hotel Plaza xin chào bạn ạ!\n\nCảm ơn bạn đã quan tâm đến dịch vụ tiệc của khách sạn. Hiện tại, hệ thống của em chưa có thông tin chi tiết về gói dịch vụ Outside Catering (cung cấp tiệc ngoài địa điểm). \n\nTuy nhiên, Aurora Hotel Plaza có Nhà hàng và Rooftop Bar với không gian rất đẹp, cùng các phòng hội nghị tiện nghi sẵn sàng phục vụ các bữa tiệc ngay tại khách sạn. Nếu bạn có nhu cầu tổ chức tiệc, hội nghị tại đây, em rất sẵn lòng tư vấn cho bạn ạ.\n\nĐối với dịch vụ Outside Catering, để em chuyển yêu cầu đến bộ phận Sự kiện & Ẩm thực của khách sạn hỗ trợ tư vấn chính xác nhất, bạn vui lòng chia sẻ giúp em **Tên gọi** và **Số điện thoại** nhé ạ! Em sẽ ghi nhận lại để bộ phận chuyên trách liên hệ trực tiếp với bạn ngay ạ.','text','0',NULL,'1','2026-04-29 13:34:00','2026-04-29 13:33:54'),
('111','21','0','guest_b0c911d6da6cff1f3d3307506654da78','customer','Thành Danh - 0938263892','text','0',NULL,'1','2026-05-02 16:16:29','2026-04-29 13:34:36'),
('112','21','0',NULL,'bot','Dạ, Aurora Hotel Plaza xin chào anh Thành Danh! Cảm ơn anh đã để lại thông tin liên hệ. Em có thể hỗ trợ gì cho anh trong chuyến đi sắp tới ạ? Anh đang muốn tìm hiểu về phòng nghỉ, cần tư vấn dịch vụ Spa, thưởng thức Rooftop Bar hay cần đặt xe đưa đón sân bay không ạ? \n\n[SAVE_CONTACT: name=Thành Danh, phone=0938263892, msg=Khách để lại thông tin liên hệ, chờ tư vấn]','text','0',NULL,'0',NULL,'2026-04-29 13:34:51'),
('113','21','0','guest_b0c911d6da6cff1f3d3307506654da78','customer','LIÊN HỆ QUA ZALO','text','0',NULL,'1','2026-05-02 16:16:29','2026-04-29 13:34:51'),
('114','21','0',NULL,'bot','Dạ, Aurora Hotel Plaza xin chào Quý khách! ????\n\nQuý khách có thể tìm kiếm và nhắn tin cho khách sạn qua ứng dụng Zalo theo số Hotline: **0251 3918 888** ạ. \n\nNgoài ra, nếu Quý khách cần hỗ trợ tư vấn phòng, đặt phòng hoặc sử dụng dịch vụ ngay bây giờ, Quý khách có thể để lại số điện thoại Zalo, chúng con sẽ chủ động liên hệ lại với Quý khách ngay nhé ạ! \n\nQuý khách đang có nhu cầu tìm hiểu về loại phòng nào hay cần hỗ trợ gì thêm không ạ?','text','0',NULL,'0',NULL,'2026-04-29 13:35:30'),
('115','21','7',NULL,'staff','Chào nhé','text','0',NULL,'0',NULL,'2026-05-02 16:30:28'),
('116','21','0',NULL,'bot','Dạ, Aurora Hotel Plaza xin chân thành chào quý khách! \n\nChúc quý khách một ngày cuối tuần thứ Bảy thật vui vẻ và rạng rỡ. Siêu trợ lý quản gia của quý khách ở đây, luôn sẵn lòng hỗ trợ. Quý khách đang có nhu cầu tìm hiểu về phòng nghỉ, đặt phòng lưu trú hay cần tư vấn về các dịch vụ tiện ích tại khách sạn ạ?','text','0',NULL,'0',NULL,'2026-05-02 16:30:38'),
