  `status` enum('open','in_progress','resolved','ignored') NOT NULL DEFAULT 'open',
  `resolved_by` int(10) unsigned DEFAULT NULL,
  `resolved_at` datetime DEFAULT NULL,
  `notes` text DEFAULT NULL COMMENT 'Ghi chú của admin',
  `last_seen_at` datetime DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_severity` (`severity`),
  KEY `idx_error_type` (`error_type`),
  KEY `idx_status` (`status`),
  KEY `idx_fingerprint` (`fingerprint`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_ai_analyzed` (`ai_analyzed`)
) ENGINE=InnoDB AUTO_INCREMENT=439 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Bảng lưu trữ lỗi AI Bug Tracker';

