-- Table structure for table `traffic_logs`
DROP TABLE IF EXISTS `traffic_logs`;
CREATE TABLE `traffic_logs` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `session_id` varchar(100) NOT NULL,
  `ip_address` varchar(45) NOT NULL,
  `user_id` int(11) DEFAULT NULL,
  `page_url` text NOT NULL,
  `page_title` varchar(255) DEFAULT NULL,
  `referer` text DEFAULT NULL,
  `user_agent` text DEFAULT NULL,
  `device_type` enum('desktop','mobile','tablet','bot') DEFAULT 'desktop',
  `is_unique` tinyint(1) DEFAULT 0,
  `bot_type` enum('good','bad','none') DEFAULT NULL,
  `bot_name` varchar(255) DEFAULT NULL,
  `visit_time` timestamp NULL DEFAULT current_timestamp(),
  `duration` int(11) DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `idx_session` (`session_id`),
  KEY `idx_visit_time` (`visit_time`),
  KEY `idx_ip` (`ip_address`)
) ENGINE=InnoDB AUTO_INCREMENT=111 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

